import React, { useState, useEffect, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import toast from 'react-hot-toast';
import { useAuth } from '../context/AuthContext';
import { timeAgo, mediaUrl } from '../utils/helpers';
import Navbar from '../components/Navbar';

export default function ExplorePage() {
  const { user: currentUser } = useAuth();
  const navigate  = useNavigate();
  const [posts, setPosts]               = useState([]);
  const [loading, setLoading]           = useState(true);
  const [selectedPost, setSelectedPost] = useState(null);

  useEffect(() => {
    axios.get('/api/posts/explore')
      .then(r => setPosts(r.data))
      .catch(() => toast.error('Failed to load explore'))
      .finally(() => setLoading(false));
  }, []);

  const handleNewPost = (post) => setPosts(p => [post, ...p]);

  const buildGrid = (posts) => {
    const sections = [];
    let i = 0, si = 0;
    while (i < posts.length) {
      const bigRight = si % 2 === 1;
      sections.push({ posts: posts.slice(i, i + 6), bigRight });
      i += 6; si++;
    }
    return sections;
  };

  const sections = buildGrid(posts);

  return (
    <div className="explore-layout">
      <Navbar onNewPost={handleNewPost} />
      <div className="explore-inner">
        <div className="explore-content">
          {loading && <ExploreSkeleton />}

          {!loading && posts.length === 0 && (
            <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', paddingTop: 80 }}>
              <div className="profile-empty__icon">
                <svg viewBox="0 0 24 24" width="33" height="33" fill="none" stroke="currentColor" strokeWidth="1.5">
                  <circle cx="12" cy="12" r="10"/><polygon points="16.24 7.76 14.12 14.12 7.76 16.24 9.88 9.88 16.24 7.76"/>
                </svg>
              </div>
              <h2 style={{ fontSize: 22, fontWeight: 300, marginBottom: 12 }}>Nothing to explore yet</h2>
              <p className="text-muted" style={{ fontSize: 14, textAlign: 'center', maxWidth: 280, lineHeight: 1.5 }}>
                Start following accounts and create posts to see content here.
              </p>
            </div>
          )}

          {!loading && posts.length > 0 && (
            <div className="explore-grid">
              {sections.map((section, si) => (
                <ExploreSection key={si} posts={section.posts} bigRight={section.bigRight} onPostClick={setSelectedPost} />
              ))}
            </div>
          )}
        </div>
      </div>

      {selectedPost && (
        <PostDetailModal
          post={selectedPost}
          currentUser={currentUser}
          onClose={() => setSelectedPost(null)}
          onDeleted={(id) => { setPosts(p => p.filter(x => x.id !== id)); setSelectedPost(null); }}
          onUpdated={(u)  => { setPosts(p => p.map(x => x.id === u.id ? { ...x, ...u } : x)); setSelectedPost(p => ({ ...p, ...u })); }}
        />
      )}
    </div>
  );
}

// ── EXPLORE SECTION ───────────────────────────────────────────
function ExploreSection({ posts, bigRight, onPostClick }) {
  if (posts.length === 0) return null;
  const topTwo      = posts.slice(1, 3);
  const bottomThree = posts.slice(3, 6);

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 3 }}>
      <div style={{ display: 'grid', gridTemplateColumns: bigRight ? '1fr 2fr' : '2fr 1fr', gridTemplateRows: '1fr 1fr', gap: 3, aspectRatio: '3/1' }}>
        {bigRight ? (
          <>
            <div style={{ display: 'flex', flexDirection: 'column', gap: 3 }}>
              {topTwo.map((p, i) => p ? <GridCell key={p.id} post={p} onClick={() => onPostClick(p)} /> : <div key={i} style={{ flex: 1, background: 'var(--bg)' }} />)}
            </div>
            <div style={{ gridRow: 'span 2' }}>
              {posts[0] && <GridCell post={posts[0]} onClick={() => onPostClick(posts[0])} big />}
            </div>
          </>
        ) : (
          <>
            <div style={{ gridRow: 'span 2' }}>
              {posts[0] && <GridCell post={posts[0]} onClick={() => onPostClick(posts[0])} big />}
            </div>
            <div style={{ display: 'flex', flexDirection: 'column', gap: 3 }}>
              {topTwo.map((p, i) => p ? <GridCell key={p.id} post={p} onClick={() => onPostClick(p)} /> : <div key={i} style={{ flex: 1, background: 'var(--bg)' }} />)}
            </div>
          </>
        )}
      </div>
      {bottomThree.length > 0 && (
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: 3 }}>
          {bottomThree.map((p, i) => p
            ? <GridCell key={p.id} post={p} onClick={() => onPostClick(p)} />
            : <div key={i} style={{ aspectRatio: '1', background: 'var(--bg)' }} />
          )}
        </div>
      )}
    </div>
  );
}

// ── GRID CELL ─────────────────────────────────────────────────
function GridCell({ post, onClick, big = false }) {
  const [hovered, setHovered] = useState(false);
  const imgUrl = mediaUrl(post.image_url);

  return (
    <div onClick={onClick}
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
      className={`grid-cell${big ? ' grid-cell--big' : ' grid-cell--aspect'}`}
      style={!big ? { aspectRatio: '1' } : {}}>
      {imgUrl
        ? <img src={imgUrl} alt="" />
        : <div style={{ width: '100%', height: '100%', minHeight: 120, background: 'var(--grad-purple)', display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 12 }}>
            <p style={{ color: '#fff', fontSize: big ? 16 : 12, textAlign: 'center', lineHeight: 1.4 }}>{post.caption}</p>
          </div>
      }
      {hovered && (
        <div className="grid-cell__hover">
          <span className={`grid-cell__stat grid-cell__stat--${big ? 'big' : 'sm'}`}>
            <svg viewBox="0 0 24 24" width={big ? 22 : 18} height={big ? 22 : 18} fill="white">
              <path d="M20.84 4.61a5.5 5.5 0 00-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 00-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 000-7.78z"/>
            </svg>
            {Number(post.likes_count).toLocaleString()}
          </span>
          <span className={`grid-cell__stat grid-cell__stat--${big ? 'big' : 'sm'}`}>
            <svg viewBox="0 0 24 24" width={big ? 22 : 18} height={big ? 22 : 18} fill="white">
              <path d="M21 15a2 2 0 01-2 2H7l-4 4V5a2 2 0 012-2h14a2 2 0 012 2z"/>
            </svg>
            {Number(post.comments_count).toLocaleString()}
          </span>
        </div>
      )}
    </div>
  );
}

// ── POST DETAIL MODAL ─────────────────────────────────────────
function PostDetailModal({ post, currentUser, onClose, onDeleted, onUpdated }) {
  const navigate = useNavigate();
  const [comments, setComments]       = useState([]);
  const [localComment, setLocalComment] = useState('');
  const [liked, setLiked]             = useState(post.user_liked > 0);
  const [likesCount, setLikesCount]   = useState(Number(post.likes_count));
  const [bookmarked, setBookmarked]   = useState(false);
  const [captionText]                 = useState(post.caption || '');
  const [sheet, setSheet]             = useState(null); // null|'menu'|'report'|'share'
  const [reportStep, setReportStep]   = useState(null);
  const cmtInputRef                   = useRef();
  const isOwn = currentUser?.id === post.user_id;
  const postUrl = `${window.location.origin}/${post.username}`;

  useEffect(() => {
    axios.get(`/api/posts/${post.id}/comments`).then(r => setComments(r.data)).catch(() => {});
  }, [post.id]);

  const toggleLike = async () => {
    setLiked(p => !p); setLikesCount(c => liked ? c - 1 : c + 1);
    await axios.post(`/api/posts/${post.id}/like`).catch(() => {});
  };
  const addComment = async e => {
    e.preventDefault(); if (!localComment.trim()) return;
    try { const { data } = await axios.post(`/api/posts/${post.id}/comments`, { text: localComment }); setComments(p => [...p, data]); setLocalComment(''); }
    catch { toast.error('Failed to comment'); }
  };
  const deletePost = async () => {
    if (!window.confirm('Delete this post?')) return;
    try { await axios.delete(`/api/posts/${post.id}`); toast.success('Post deleted'); onDeleted(post.id); }
    catch { toast.error('Failed to delete'); }
  };

  const closeSheet = () => { setSheet(null); setReportStep(null); };
  const av     = mediaUrl(post.avatar);
  const imgUrl = mediaUrl(post.image_url);
  const init   = (post.username || 'U')[0].toUpperCase();
  const avatarEl = av
    ? <img src={av} alt="" className="avatar avatar--32" style={{ cursor: 'pointer' }} onClick={() => { onClose(); navigate(`/${post.username}`); }} />
    : <div className="avatar-ph avatar-ph--32" style={{ cursor: 'pointer' }} onClick={() => { onClose(); navigate(`/${post.username}`); }}>{init}</div>;

  return (
    <div className="overlay overlay--dark" onClick={e => e.target === e.currentTarget && onClose()}>
      <button onClick={onClose} style={{ position: 'fixed', top: 16, right: 16, background: 'none', border: 'none', cursor: 'pointer', color: '#fff', fontSize: 32, lineHeight: 1, zIndex: 2001 }}>×</button>
      <div className="post-detail">
        <div className="post-detail__img">
          {imgUrl
            ? <img src={imgUrl} alt="post" />
            : <div style={{ width: '100%', height: '100%', background: 'var(--grad-purple)', display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 24 }}>
                <p style={{ color: '#fff', fontSize: 18, textAlign: 'center' }}>{captionText}</p>
              </div>
          }
        </div>
        <div className="post-detail__side">
          <div className="post-detail__hdr">
            <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
              {avatarEl}
              <span className="font-semi" style={{ fontSize: 14, cursor: 'pointer' }}
                onClick={() => { onClose(); navigate(`/${post.username}`); }}>{post.username}</span>
            </div>
            <button onClick={() => setSheet('menu')} className="post-card__dots-btn" aria-label="More options">
              <svg viewBox="0 0 24 24" width="20" height="20" fill="currentColor">
                <circle cx="5" cy="12" r="1.5"/><circle cx="12" cy="12" r="1.5"/><circle cx="19" cy="12" r="1.5"/>
              </svg>
            </button>
          </div>

          <div className="post-detail__scroll">
            {captionText && (
              <div style={{ display: 'flex', gap: 10, marginBottom: 16 }}>
                {avatarEl}
                <p style={{ fontSize: 14, lineHeight: 1.5, margin: 0 }}><strong>{post.username}</strong> {captionText}</p>
              </div>
            )}
            {comments.length === 0 && !captionText && (
              <div style={{ textAlign: 'center', padding: '40px 0' }} className="text-muted">No comments yet.</div>
            )}
            {comments.map(c => {
              const ca = mediaUrl(c.avatar); const ci = (c.username || 'U')[0].toUpperCase();
              return (
                <div key={c.id} style={{ display: 'flex', gap: 10, marginBottom: 12 }}>
                  {ca ? <img src={ca} alt="" className="avatar avatar--32" /> : <div className="avatar-ph avatar-ph--32">{ci}</div>}
                  <div>
                    <p style={{ fontSize: 14, lineHeight: 1.5, margin: 0 }}><strong>{c.username}</strong> {c.text}</p>
                    <span className="text-muted" style={{ fontSize: 11 }}>{timeAgo(c.created_at)}</span>
                  </div>
                </div>
              );
            })}
          </div>

          <div className="post-detail__actions">
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 8 }}>
              <div style={{ display: 'flex', gap: 14 }}>
                <button onClick={toggleLike} className="icon-btn">
                  <svg viewBox="0 0 24 24" width="24" height="24" fill={liked ? 'var(--danger)' : 'none'} stroke={liked ? 'var(--danger)' : 'currentColor'} strokeWidth="2"
                    style={{ transition: 'transform .15s', transform: liked ? 'scale(1.15)' : 'scale(1)' }}>
                    <path d="M20.84 4.61a5.5 5.5 0 00-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 00-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 000-7.78z"/>
                  </svg>
                </button>
                {/* Comment icon — focus input */}
                <button className="icon-btn" onClick={() => cmtInputRef.current?.focus()}>
                  <svg viewBox="0 0 24 24" width="24" height="24" fill="none" stroke="currentColor" strokeWidth="2">
                    <path d="M21 15a2 2 0 01-2 2H7l-4 4V5a2 2 0 012-2h14a2 2 0 012 2z"/>
                  </svg>
                </button>
                {/* Share icon */}
                <button className="icon-btn" onClick={() => setSheet('share')}>
                  <svg viewBox="0 0 24 24" width="24" height="24" fill="none" stroke="currentColor" strokeWidth="2">
                    <line x1="22" y1="2" x2="11" y2="13"/><polygon points="22 2 15 22 11 13 2 9 22 2"/>
                  </svg>
                </button>
              </div>
              <button onClick={() => { setBookmarked(p => !p); toast.success(bookmarked ? 'Removed from saved' : 'Saved!'); }} className="icon-btn">
                <svg viewBox="0 0 24 24" width="24" height="24" fill={bookmarked ? 'currentColor' : 'none'} stroke="currentColor" strokeWidth="2">
                  <path d="M19 21l-7-5-7 5V5a2 2 0 012-2h10a2 2 0 012 2z"/>
                </svg>
              </button>
            </div>
            <div className="font-bold" style={{ fontSize: 14, marginBottom: 4 }}>{likesCount.toLocaleString()} {likesCount === 1 ? 'like' : 'likes'}</div>
            <div className="text-muted" style={{ fontSize: 11, textTransform: 'uppercase' }}>{timeAgo(post.created_at)}</div>
          </div>

          <form onSubmit={addComment} className="post-detail__cmt-form">
            <svg viewBox="0 0 24 24" width="24" height="24" fill="none" stroke="#8e8e8e" strokeWidth="1.5" style={{ flexShrink: 0 }}>
              <circle cx="12" cy="12" r="10"/><path d="M8 14s1.5 2 4 2 4-2 4-2M9 9h.01M15 9h.01"/>
            </svg>
            <input ref={cmtInputRef} value={localComment} onChange={e => setLocalComment(e.target.value)}
              placeholder="Add a comment..." style={{ flex: 1, border: 'none', outline: 'none', fontSize: 14 }} />
            {localComment && <button type="submit" className="btn btn--accent font-bold" style={{ fontSize: 14, flexShrink: 0 }}>Post</button>}
          </form>
        </div>
      </div>

      {/* Sheet modals */}
      {sheet === 'menu' && (
        <div className="ig-sheet-overlay" onClick={e => e.target === e.currentTarget && closeSheet()}>
          <div className="ig-sheet">
            {isOwn ? (
              <>
                <button className="ig-sheet__btn ig-sheet__btn--danger" onClick={deletePost}>Delete</button>
                <button className="ig-sheet__btn" onClick={() => { navigator.clipboard.writeText(postUrl); toast.success('Link copied!'); closeSheet(); }}>Copy link</button>
                <button className="ig-sheet__btn ig-sheet__btn--bold" onClick={closeSheet}>Cancel</button>
              </>
            ) : (
              <>
                <button className="ig-sheet__btn ig-sheet__btn--danger" onClick={() => { setReportStep(null); setSheet('report'); }}>Report</button>
                <button className="ig-sheet__btn" onClick={() => setSheet('share')}>Share to…</button>
                <button className="ig-sheet__btn" onClick={() => { navigator.clipboard.writeText(postUrl); toast.success('Link copied!'); closeSheet(); }}>Copy link</button>
                <button className="ig-sheet__btn" onClick={() => { onClose(); navigate(`/${post.username}`); }}>About this account</button>
                <button className="ig-sheet__btn ig-sheet__btn--bold" onClick={closeSheet}>Cancel</button>
              </>
            )}
          </div>
        </div>
      )}

      {sheet === 'report' && (
        <div className="ig-sheet-overlay" onClick={e => e.target === e.currentTarget && closeSheet()}>
          <div className="ig-sheet">
            {!reportStep ? (
              <>
                <div className="ig-sheet__title">Why are you reporting this?</div>
                {["It's spam","Nudity or sexual activity","Hate speech or symbols","Violence or dangerous organisations","Bullying or harassment","False information","I just don't like it"].map(r => (
                  <button key={r} className="ig-sheet__btn" style={{ textAlign: 'left', display: 'flex', justifyContent: 'space-between' }} onClick={() => setReportStep(r)}>
                    <span>{r}</span>
                    <svg viewBox="0 0 24 24" width="16" height="16" fill="none" stroke="var(--text-muted)" strokeWidth="2"><path d="M9 18l6-6-6-6"/></svg>
                  </button>
                ))}
                <button className="ig-sheet__btn ig-sheet__btn--bold" onClick={closeSheet}>Cancel</button>
              </>
            ) : (
              <>
                <div className="sheet-report-confirm">
                  <div className="sheet-report-confirm__icon">
                    <svg viewBox="0 0 24 24" width="44" height="44" fill="none" stroke="var(--text-primary)" strokeWidth="1.5"><path d="M22 11.08V12a10 10 0 11-5.93-9.14"/><polyline points="22 4 12 14.01 9 11.01"/></svg>
                  </div>
                  <h3 className="sheet-report-confirm__title">Thanks for letting us know</h3>
                  <p className="sheet-report-confirm__body">Your report for <strong>{reportStep}</strong> has been submitted.</p>
                </div>
                <button className="ig-sheet__btn" onClick={closeSheet}>Done</button>
              </>
            )}
          </div>
        </div>
      )}

      {sheet === 'share' && (
        <ExploreShareSheet post={post} postUrl={postUrl} currentUser={currentUser} onClose={closeSheet} />
      )}
    </div>
  );
}

// ── SKELETON ──────────────────────────────────────────────────
function ExploreSkeleton() {
  return (
    <div>
      {[0, 1].map(i => (
        <div key={i} style={{ marginBottom: 3 }}>
          <div style={{ display: 'grid', gridTemplateColumns: i % 2 === 0 ? '2fr 1fr' : '1fr 2fr', gap: 3, marginBottom: 3 }}>
            <div className="shimmer" style={{ aspectRatio: '1', gridRow: 'span 2' }} />
            <div style={{ display: 'flex', flexDirection: 'column', gap: 3 }}>
              <div className="shimmer" style={{ flex: 1, minHeight: 100 }} />
              <div className="shimmer" style={{ flex: 1, minHeight: 100 }} />
            </div>
          </div>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3,1fr)', gap: 3 }}>
            {[0, 1, 2].map(j => <div key={j} className="shimmer" style={{ aspectRatio: '1' }} />)}
          </div>
        </div>
      ))}
    </div>
  );
}

// ── EXPLORE SHARE SHEET ───────────────────────────────────────
function ExploreShareSheet({ post, postUrl, currentUser, onClose }) {
  const [query, setQuery]     = useState('');
  const [results, setResults] = useState([]);
  const [loading, setLoading] = useState(false);
  const [sent, setSent]       = useState({});
  const debounce              = useRef();

  useEffect(() => {
    axios.get('/api/users/suggestions').then(r => setResults(r.data)).catch(() => {});
  }, []);

  useEffect(() => {
    clearTimeout(debounce.current);
    if (!query.trim()) { axios.get('/api/users/suggestions').then(r => setResults(r.data)).catch(() => {}); return; }
    setLoading(true);
    debounce.current = setTimeout(async () => {
      try { const { data } = await axios.get(`/api/users/search?q=${encodeURIComponent(query)}`); setResults(data); }
      catch { setResults([]); } finally { setLoading(false); }
    }, 300);
    return () => clearTimeout(debounce.current);
  }, [query]);

  const sendTo = async (userId, username) => {
    if (sent[userId]) return;
    const payload = JSON.stringify({ type: 'post_share', post_id: post.id, image_url: post.image_url || null, caption: post.caption || '', username: post.username });
    try { await axios.post(`/api/messages/${userId}`, { text: payload }); setSent(s => ({ ...s, [userId]: true })); toast.success(`Sent to ${username}!`); }
    catch { toast.error('Failed to send'); }
  };

  return (
    <div className="ig-sheet-overlay" onClick={e => e.target === e.currentTarget && onClose()}>
      <div className="ig-sheet">
        <div className="ig-sheet__title">Share</div>
        <div style={{ padding: '8px 16px 12px' }}>
          <div className="search-box" style={{ background: 'var(--border-light)' }}>
            <svg viewBox="0 0 24 24" width="16" height="16" fill="none" stroke="#8e8e8e" strokeWidth="2" style={{ flexShrink: 0 }}><circle cx="11" cy="11" r="8"/><path d="M21 21l-4.35-4.35"/></svg>
            <input value={query} onChange={e => setQuery(e.target.value)} placeholder="Search" className="search-box__input" autoFocus />
          </div>
        </div>
        <div onClick={() => { navigator.clipboard.writeText(postUrl).then(() => toast.success('Link copied!')); onClose(); }} className="ig-share-copy-row">
          <div className="ig-share-copy-icon">
            <svg viewBox="0 0 24 24" width="22" height="22" fill="none" stroke="var(--text-primary)" strokeWidth="2"><path d="M10 13a5 5 0 007.54.54l3-3a5 5 0 00-7.07-7.07l-1.72 1.71"/><path d="M14 11a5 5 0 00-7.54-.54l-3 3a5 5 0 007.07 7.07l1.71-1.71"/></svg>
          </div>
          <span style={{ fontSize: 14, fontWeight: 600 }}>Copy link</span>
        </div>
        <div style={{ maxHeight: '40vh', overflowY: 'auto' }}>
          {loading && <div style={{ padding: 20, textAlign: 'center' }} className="text-muted">Searching…</div>}
          {!loading && results.filter(u => u.id !== currentUser?.id).map(u => {
            const uAv = mediaUrl(u.avatar); const uInit = (u.username || 'U')[0].toUpperCase(); const wasSent = !!sent[u.id];
            return (
              <div key={u.id} style={{ display: 'flex', alignItems: 'center', gap: 12, padding: '10px 16px' }}>
                <div style={{ flexShrink: 0 }}>{uAv ? <img src={uAv} alt="" className="avatar avatar--44" /> : <div className="avatar-ph avatar-ph--44">{uInit}</div>}</div>
                <div style={{ flex: 1, minWidth: 0 }}>
                  <div className="truncate font-semi" style={{ fontSize: 14 }}>{u.username}</div>
                  {u.full_name && <div className="truncate text-muted" style={{ fontSize: 13 }}>{u.full_name}</div>}
                </div>
                <button onClick={() => sendTo(u.id, u.username)} className={wasSent ? 'btn btn--secondary' : 'btn btn--primary'} style={{ flexShrink: 0, fontSize: 13, padding: '6px 18px' }} disabled={wasSent}>
                  {wasSent ? 'Sent' : 'Send'}
                </button>
              </div>
            );
          })}
        </div>
        <div style={{ padding: '8px 16px 4px', borderTop: '1px solid var(--border-light)' }}>
          <button className="ig-sheet__btn ig-sheet__btn--bold" onClick={onClose}>Cancel</button>
        </div>
      </div>
    </div>
  );
}
